class ElementFormatter{get customEmotes(){return/(:don:|:katsu:|:desuwa:|:dirt:|:armagan:)/g}get emojiTable(){return{don:"/static/svg/don.svg",katsu:"/static/svg/katsu.svg",desuwa:"/static/svg/desuwa.svg",dirt:"/static/image/dirt_small.gif",armagan:"/static/image/armagan_small.gif"}}formatAll(){this.dateFormat(),this.markdownFormat(),this.twemojiFormat(),this.emoteFormat()}dateFormat(){for(let t of document.getElementsByClassName("date-format"))try{t.innerHTML=luxon.DateTime.fromISO(t.innerHTML).toFormat("fff")}catch(t){console.error(t)}}markdownFormat(){for(let t of document.getElementsByClassName("markdown-format")){let e=new showdown.Converter;try{t.innerHTML=e.makeHtml(t.innerHTML)}catch(t){console.error(t)}}}twemojiFormat(){for(let t of document.getElementsByClassName("twemoji-format"))try{twemoji.parse(t)}catch(t){console.error(t)}}emoteFormat(){for(let t of document.getElementsByClassName("emote-format"))try{t.innerHTML=t.innerHTML.replace(this.customEmotes,t=>{let e=document.createElement("img");return e.src=this.emojiTable[t.replace(/:/g,"")],e.className="emoji",e.draggable=!1,e.alt=t,e.outerHTML})}catch(t){console.error(t)}}}export{ElementFormatter};